window.MOD_DATA={"id": 2, "slug": "conectar", "title": "Conectar", "sub": "Conjunções e conectivos — ligar ideias com lógica", "icon": "🔗", "items": [{"file": "01_AND_E_Adicao.pdf", "word": "AND", "pt": "E", "desc": "Conecta palavras, frases ou ideias — adição simples", "usos": [{"title": "AND une duas coisas (substantivos, adjetivos)", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["noun + noun", "I have a dog and a cat.", "Eu tenho um cachorro e um gato."], ["noun + noun", "She likes coffee and tea.", "Ela gosta de café e chá."], ["adj + adj", "The house is big and beautiful.", "A casa é grande e bonita."], ["adj + adj", "He is smart and kind.", "Ele é inteligente e gentil."], ["verb + verb", "I cook and clean every day.", "Eu cozinho e limpo todo dia."], ["em lista", "I need eggs, milk, and bread.", "Preciso de ovos, leite e pão."]], "notes": ["💡 Em listas com 3+ itens, AND vem antes do ÚLTIMO item. A vírgula antes do AND (vírgula de Oxford) é opcional mas comum."]}, {"title": "AND une duas orações completas", "num": 2, "header": ["Tempo", "Inglês", "Português"], "rows": [["Presente", "I study English and she studies Spanish.", "Eu estudo inglês e ela estuda espanhol."], ["Passado", "He woke up early and went to the gym.", "Ele acordou cedo e foi à academia."], ["Futuro", "We will eat dinner and watch a movie.", "Vamos jantar e assistir a um filme."], ["Neg.", "I don't drink coffee and I don't smoke.", "Eu não bebo café e não fumo."], ["Pergunta", "Do you work and study at the same time?", "Você trabalha e estuda ao mesmo tempo?"]], "notes": ["⚠️ AND não indica contraste — só adição. Para contraste use BUT."]}, {"title": "AND em expressões fixas do dia a dia", "num": 3, "header": ["Expressão", "Inglês", "Português"], "rows": [["come and go", "People come and go all the time.", "As pessoas vão e vêm o tempo todo."], ["again and again", "She tried again and again.", "Ela tentou repetidamente."], ["more and more", "It's getting more and more expensive.", "Está ficando cada vez mais caro."], ["sooner or later", "AND também aparece em: now and then.", "AND também em: de vez em quando."], ["try and do", "Try and relax. (= Try to relax)", "Tente relaxar. (informal)"]], "notes": ["💡 'Try and' é informal para 'try to'. Muito usado na fala americana: 'Come and see me' = 'Come to see me'.", "🔴 ERRO COMUM: 'I am tired and hungry and I want to sleep and eat.' — usar AND demais deixa a fala infantil. Varie com BUT, SO, ALSO...", "💡 RESUMO: AND = e / também / além disso (adição). Une substantivos, adjetivos, verbos e orações inteiras."]}], "notes": [], "resumo": "💡 RESUMO: AND = e / também / além disso (adição). Une substantivos, adjetivos, verbos e orações inteiras.", "module": 2}, {"file": "01_SINCE_Desde_Ja_Que.pdf", "word": "SINCE", "pt": "DESDE / DESDE QUE / POIS / JÁ QUE", "desc": "Dois usos principais: TEMPO (desde quando) e RAZÃO (já que / como)", "usos": [{"title": "SINCE = DESDE (ponto de início no tempo)", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["ponto fixo", "I have lived here since 2018.", "Eu moro aqui desde 2018."], ["ponto fixo", "She has worked there since January.", "Ela trabalha lá desde janeiro."], ["ponto fixo", "I haven't seen him since Monday.", "Não o vi desde segunda-feira."], ["ponto fixo", "He has been sick since last week.", "Ele está doente desde a semana passada."], ["evento", "I've felt better since I started exercising.", "Me sinto melhor desde que comecei a me exercitar."]], "notes": ["⚠️ SINCE de tempo usa Present Perfect (have/has + particípio). Indica um ponto de início que continua até AGORA."]}, {"title": "SINCE vs FOR (ambos com Present Perfect)", "num": 2, "header": ["Palavra", "Uso", "Inglês", "Português"], "rows": [["SINCE", "ponto de início", "I've lived here since 2018.", "Moro aqui desde 2018 (ponto fixo)."], ["FOR", "duração total", "I've lived here for 6 years.", "Moro aqui há 6 anos (período)."], ["SINCE", "ponto de início", "She's worked here since Monday.", "Ela trabalha aqui desde segunda."], ["FOR", "duração total", "She's worked here for 3 days.", "Ela trabalha aqui há 3 dias."], ["SINCE", "ponto de início", "I haven't slept since yesterday.", "Não durmo desde ontem."], ["FOR", "duração total", "I haven't slept for 24 hours.", "Não durmo há 24 horas."]], "notes": ["💡 SINCE = desde QUANDO (ponto específico: 2018, Monday, yesterday) | FOR = há QUANTO TEMPO (período: 6 years, 3 days, 2 hours)."]}, {"title": "SINCE = COMO / JÁ QUE / POIS (razão conhecida)", "num": 3, "header": ["Estrutura", "Inglês", "Português"], "rows": [["razão", "Since you're here, let's start the meeting.", "Já que você está aqui, vamos começar a reunião."], ["razão", "Since it's late, we should go.", "Como está tarde, devemos ir."], ["razão", "Since she knows the answer, ask her.", "Já que ela sabe a resposta, pergunte a ela."], ["razão", "Since I was tired, I went to bed early.", "Como estava cansado, fui dormir cedo."], ["razão", "Since you asked, I'll tell you the truth.", "Já que você perguntou, vou te dizer a verdade."]], "notes": ["💡 SINCE (razão) = BECAUSE, mas implica que a razão já é ÓBVIA ou CONHECIDA pelo ouvinte. Mais formal que BECAUSE."]}, {"title": "SINCE THEN = DESDE ENTÃO", "num": 4, "header": ["Expressão", "Inglês", "Português"], "rows": [["since then", "I met her in 2020. Since then, we've been friends.", "Conheci ela em 2020. Desde então, somos amigas."], ["ever since", "He left. Ever since, I've missed him.", "Ele foi embora. Desde então, sinto saudade."], ["since then", "I started exercising. Since then, I feel better.", "Comecei a me exercitar. Desde então, me sinto melhor."], ["long since", "That restaurant has long since closed.", "Aquele restaurante fechou há muito tempo."], ["THEN = desde então.", "", ""]], "notes": ["💡 SINCE THEN = 'desde então' — muito útil para contar histórias e conectar eventos no passado com o presente.", "🔴 ❌ ✅ ERRO COMUM: 'I live here since 2018.' — SINCE de tempo exige Present Perfect: 'I HAVE LIVED here since 2018.'", "💡 RESUMO: SINCE = desde (tempo, com Present Perfect) | SINCE = já que/como (razão formal) | SINCE vs FOR: ponto de início vs duração total | SINCE"]}], "notes": [], "resumo": "💡 RESUMO: SINCE = desde (tempo, com Present Perfect) | SINCE = já que/como (razão formal) | SINCE vs FOR: ponto de início vs duração total | SINCE", "module": 2}, {"file": "02_BUT_Mas_Porem.pdf", "word": "BUT", "pt": "MAS / PORÉM", "desc": "Contrasta duas ideias — a segunda surpreende ou contradiz a primeira", "usos": [{"title": "BUT = MAS (contraste direto)", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["adj x adj", "The food is cheap but delicious.", "A comida é barata mas deliciosa."], ["ação x ação", "I want to go but I'm tired.", "Quero ir mas estou cansado."], ["ação x ação", "She studies hard but she doesn't pass.", "Ela estuda muito mas não passa."], ["fato x fato", "It's raining but it's warm.", "Está chovendo mas está quente."], ["passado", "He tried but he couldn't do it.", "Ele tentou mas não conseguiu."], ["futuro", "I will go but I won't stay long.", "Vou ir mas não vou ficar muito."]], "notes": ["⚠️ BUT sempre indica SURPRESA ou CONTRADIÇÃO. A segunda parte é inesperada em relação à primeira."]}, {"title": "BUT = EXCETO / MENOS (exclusão)", "num": 2, "header": ["Contexto", "Inglês", "Português"], "rows": [["exclusão", "Everyone came but Maria.", "Todo mundo veio menos a Maria."], ["exclusão", "I eat everything but seafood.", "Eu como tudo menos frutos do mar."], ["exclusão", "Nothing but the truth.", "Nada além da verdade."], ["exclusão", "The last but one = penúltimo.", "The last but one = penúltimo."]], "notes": ["💡 Nesse uso, BUT = EXCEPT (exceto). 'All but one' = todos menos um."]}, {"title": "NOT… BUT (não… mas sim)", "num": 3, "header": ["Contexto", "Inglês", "Português"], "rows": [["correção", "It's not cold but warm.", "Não está frio, mas sim quente."], ["correção", "I didn't call her but texted her.", "Não liguei mas mandei mensagem."], ["correção", "Not him but her brother came.", "Não ele, mas sim o irmão dela veio."]], "notes": ["💡 NOT… BUT é usado para CORRIGIR uma informação: 'Não X, mas sim Y'."]}, {"title": "BUT em expressões do dia a dia", "num": 4, "header": ["Expressão", "Inglês", "Português"], "rows": [["but anyway", "It was hard, but anyway, I did it.", "Foi difícil, mas de qualquer forma, eu fiz."], ["but still", "She's rude, but still I like her.", "Ela é grossa, mas mesmo assim gosto dela."], ["but then again", "I'm tired, but then again, I'll go.", "Estou cansado, mas pensando bem, vou."], ["but wait", "But wait, there's more!", "Mas espera, tem mais!"], ["aceito.", "", ""]], "notes": ["💡 Expressões com BUT são muito usadas na fala. 'But still' e 'but anyway' aparecem muito em conversas informais.", "🔴 ERRO COMUM: 'I am tired. But I will go.' — BUT geralmente une duas orações na MESMA frase, não inicia frase separada em escrita formal. Na fala é", "💡 RESUMO: BUT = mas / porém (contraste) | BUT = exceto / menos (exclusão) | NOT…BUT = não X mas sim Y."]}], "notes": [], "resumo": "💡 RESUMO: BUT = mas / porém (contraste) | BUT = exceto / menos (exclusão) | NOT…BUT = não X mas sim Y.", "module": 2}, {"file": "02_UNTIL_Ate.pdf", "word": "UNTIL / TILL", "pt": "ATÉ / ATÉ QUE", "desc": "Indicam o limite temporal de uma ação — até quando algo dura ou acontece", "usos": [{"title": "UNTIL = ATÉ / ATÉ QUE (limite no tempo)", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["limite", "I'll wait until you arrive.", "Vou esperar até você chegar."], ["limite", "She worked until midnight.", "Ela trabalhou até meia-noite."], ["limite", "Until now, everything was fine.", "Até agora, tudo estava bem."], ["limite", "Don't leave until I get back.", "Não saia até eu voltar."], ["limite", "I'll stay until the party ends.", "Vou ficar até a festa acabar."], ["limite", "He didn't sleep until 3am.", "Ele não dormiu até as 3h da manhã."]], "notes": ["⚠️ UNTIL indica o PONTO FINAL de uma ação — a ação continua ATÉ esse momento e para depois."]}, {"title": "TILL = ATÉ (informal, sinônimo de UNTIL)", "num": 2, "header": ["Estrutura", "Inglês", "Português"], "rows": [["informal", "Wait till I finish.", "Espera até eu terminar."], ["informal", "She'll be here till Friday.", "Ela ficará aqui até sexta."], ["informal", "I slept till noon.", "Dormi até o meio-dia."], ["informal", "Don't stop till you're done.", "Não pare até terminar."]], "notes": ["💡 TILL e UNTIL têm o MESMO significado. TILL é mais informal e comum na fala. UNTIL é mais comum na escrita formal."]}, {"title": "NOT…UNTIL = SÓ QUANDO / NÃO…ATÉ", "num": 3, "header": ["Estrutura", "Inglês", "Português"], "rows": [["not…until", "I didn't sleep until 3am.", "Só dormi às 3h da manhã."], ["not…until", "She didn't stop until she finished.", "Ela só parou quando terminou."], ["not…until", "He didn't call until he arrived.", "Ele só ligou quando chegou."], ["not…until", "Don't start until I say so.", "Não comece até eu mandar."]], "notes": ["💡 NOT…UNTIL = ação só acontece naquele momento. 'I didn't sleep until 3am' = 'Só dormi às 3h.' — muito usado!"]}, {"title": "UNTIL vs BY (ambos relacionados a tempo)", "num": 4, "header": ["Palavra", "Significado", "Inglês", "Português"], "rows": [["UNTIL", "ação dura até esse ponto", "I'll wait until 5pm.", "Vou esperar até as 17h."], ["BY", "prazo (não passa disso)", "Finish it by 5pm.", "Termine até as 17h (prazo)."], ["UNTIL", "ação contínua", "She studied until midnight.", "Ela estudou até meia-noite."], ["BY", "deadline", "Submit the form by Friday.", "Envie o formulário até sexta."]], "notes": ["⚠️ UNTIL = ação que continua até esse momento | BY = prazo/deadline (o momento limite para algo ser feito).", "🔴 ❌ ✅ ERRO COMUM: 'I'll wait until you will arrive.' — Depois de UNTIL no futuro, usa-se PRESENTE SIMPLES: 'I'll wait until you ARRIVE.'", "💡 RESUMO: UNTIL / TILL = até / até que (limite temporal, ação contínua) | NOT…UNTIL = só quando | TILL = informal | UNTIL vs BY: continua até vs prazo."]}], "notes": [], "resumo": "💡 RESUMO: UNTIL / TILL = até / até que (limite temporal, ação contínua) | NOT…UNTIL = só quando | TILL = informal | UNTIL vs BY: continua até vs prazo.", "module": 2}, {"file": "03_AS_SOON_AS_Assim_Que.pdf", "word": "AS SOON AS / ONCE / MEANWHILE", "pt": "ASSIM QUE / UMA", "desc": "VEZ QUE / ENQUANTO ISSO", "usos": [{"title": "AS SOON AS = ASSIM QUE / MAL (imediatamente após)", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["imediato", "As soon as I arrive, I'll call you.", "Assim que eu chegar, vou te ligar."], ["imediato", "As soon as she heard the news, she cried.", "Assim que ela ouviu a notícia, ela chorou."], ["imediato", "Leave as soon as you finish.", "Saia assim que terminar."], ["imediato", "As soon as the rain stops, we'll go.", "Assim que a chuva parar, vamos."], ["imediato", "I recognized him as soon as I saw him.", "Reconheci ele assim que o vi."]], "notes": ["💡 AS SOON AS = 'assim que' — indica que a segunda ação acontece IMEDIATAMENTE após a primeira. Muito usado no dia a dia."]}, {"title": "ONCE = UMA VEZ QUE / ASSIM QUE (após uma conclusão)", "num": 2, "header": ["Estrutura", "Inglês", "Português"], "rows": [["conclusão", "Once you finish, you can leave.", "Uma vez que você terminar, pode ir."], ["conclusão", "Once she understood, she improved fast.", "Assim que ela entendeu, melhorou rápido."], ["conclusão", "Once the contract is signed, we'll start.", "Uma vez que o contrato estiver assinado, começamos."], ["conclusão", "Call me once you're done.", "Me ligue assim que terminar."], ["conclusão", "Once you try it, you'll love it.", "Uma vez que você experimentar, vai amar."]], "notes": ["💡 ONCE = 'uma vez que' / 'assim que' — indica que algo se torna possível ou acontece APÓS uma condição ser concluída."]}, {"title": "MEANWHILE = ENQUANTO ISSO / NESSE MEIO TEMPO", "num": 3, "header": ["Estrutura", "Inglês", "Português"], "rows": [["paralelo", "She cooked dinner. Meanwhile, he set the table.", "Ela cozinhou o jantar. Enquanto isso, ele pôs a mesa."], ["paralelo", "I'll prepare the report. Meanwhile, you call them.", "Vou preparar o relatório. Enquanto isso, você liga para eles."], ["paralelo", "The kids played outside. Meanwhile, mom worked.", "As crianças brincavam do lado de fora. Enquanto isso, a mãe trabalhava."], ["paralelo", "He was sleeping. Meanwhile, the world changed.", "Ele estava dormindo. Enquanto isso, o mundo mudou."]], "notes": ["⚠️ MEANWHILE sempre inicia a segunda frase e indica que DUAS COISAS acontecem ao MESMO TEMPO em contextos diferentes."]}, {"title": "AS SOON AS vs ONCE vs WHEN (comparação)", "num": 4, "header": ["Palavra", "Ênfase", "Exemplo", "Tradução"], "rows": [["WHEN", "momento", "Call me when you arrive.", "Me ligue quando chegar."], ["AS SOON AS", "imediatamente", "Call me as soon as you arrive.", "Me ligue assim que chegar (imediato!)."], ["ONCE", "após concluir", "Call me once you've settled in.", "Me ligue uma vez que estiver instalado."], ["MEANWHILE", "ações paralelas", "I'll wait. Meanwhile, you prepare.", "Vou esperar. Enquanto isso, você prepara."]], "notes": ["💡 AS SOON AS é mais urgente que WHEN. ONCE implica conclusão antes da próxima ação. MEANWHILE indica paralelismo."]}, {"title": "Expressões fixas do dia a dia", "num": 5, "header": ["Expressão", "Inglês", "Português"], "rows": [["as soon as possible", "I'll answer as soon as possible.", "Vou responder o mais breve possível."], ["ASAP", "Reply ASAP, please.", "Responda o quanto antes, por favor."], ["in the meantime", "In the meantime, relax.", "Nesse meio tempo, relaxe."], ["for the time being", "Stay here for the time being.", "Fique aqui por enquanto."], ["once in a while", "I visit them once in a while.", "Eu os visito de vez em quando."], ["as soon as possible.", "", ""]], "notes": ["💡 'As soon as possible' = ASAP — uma das expressões mais usadas em inglês profissional. 'Once in a while' = de vez em quando.", "🔴 ❌ ✅ ERRO COMUM: 'As soon as I will finish, I'll call.' — Depois de AS SOON AS no futuro, usa-se PRESENTE: 'As soon as I FINISH, I'll call.'", "💡 RESUMO: AS SOON AS = assim que (imediato) | ONCE = uma vez que/assim que (após conclusão) | MEANWHILE = enquanto isso (paralelo) | ASAP ="]}], "notes": [], "resumo": "💡 RESUMO: AS SOON AS = assim que (imediato) | ONCE = uma vez que/assim que (após conclusão) | MEANWHILE = enquanto isso (paralelo) | ASAP =", "module": 2}, {"file": "03_OR_Ou_Alternativa.pdf", "word": "OR", "pt": "OU", "desc": "Apresenta alternativas ou opções — uma coisa ou a outra", "usos": [{"title": "OR = OU (alternativa)", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["opção", "Do you want tea or coffee?", "Você quer chá ou café?"], ["opção", "You can call or send a message.", "Você pode ligar ou mandar mensagem."], ["opção", "Is she American or British?", "Ela é americana ou britânica?"], ["lista", "Red, blue, or green — choose one.", "Vermelho, azul ou verde — escolha um."], ["futuro", "We'll go by bus or by train.", "Vamos de ônibus ou de trem."], ["pergunta", "Did he call or text you?", "Ele ligou ou mandou mensagem?"]], "notes": ["💡 OR apresenta ESCOLHA entre duas ou mais opções. Nas perguntas, indica que uma das opções é esperada como resposta."]}, {"title": "OR = SENÃO / CASO CONTRÁRIO (consequência negativa)", "num": 2, "header": ["Contexto", "Inglês", "Português"], "rows": [["ameaça suave", "Hurry up or we'll be late.", "Apresse-se ou vamos nos atrasar."], ["consequência", "Eat your vegetables or no dessert.", "Coma as verduras ou não tem sobremesa."], ["aviso", "Be careful or you'll fall.", "Tome cuidado ou você vai cair."], ["aviso", "Call her or she'll be worried.", "Ligue para ela ou ela vai se preocupar."]], "notes": ["⚠️ Nesse uso, OR = 'senão' / 'caso contrário'. A segunda parte é a CONSEQUÊNCIA de não fazer a primeira."]}, {"title": "EITHER…OR e NEITHER…NOR", "num": 3, "header": ["Estrutura", "Inglês", "Português"], "rows": [["either…or", "You can either stay or go.", "Você pode ficar ou ir — escolha."], ["either…or", "Either she calls or I will.", "Ou ela liga ou eu ligo."], ["neither…nor", "Neither he nor she came.", "Nem ele nem ela vieram."], ["neither…nor", "I have neither time nor money.", "Não tenho nem tempo nem dinheiro."]], "notes": ["💡 EITHER…OR = 'ou… ou' (escolha). NEITHER…NOR = 'nem… nem' (negação dupla)."]}, {"title": "OR em explicações e reformulações", "num": 4, "header": ["Contexto", "Inglês", "Português"], "rows": [["explicação", "Call the police, or at least security.", "Chame a polícia, ou pelo menos a segurança."], ["reformulação", "She's my cousin, or sort of.", "Ela é minha prima, ou algo assim."], ["aproximação", "It takes an hour or so.", "Leva uma hora mais ou menos."], ["aproximação", "20 or 30 people were there.", "Umas 20 ou 30 pessoas estavam lá."], ["= mais ou menos.", "", ""]], "notes": ["💡 'Or so' = 'mais ou menos'. 'Or at least' = 'ou pelo menos'. Muito usados na fala para suavizar afirmações.", "🔴 ✅ ERRO COMUM: 'I don't like coffee or tea' — aqui OR é correto em negativas. Mas em afirmativas usa-se AND: 'I like coffee and tea' / 'I like coffee or", "tea' ❌ (só se for alternativa real).", "💡 RESUMO: OR = ou (alternativa/escolha) | OR = senão/caso contrário (consequência) | EITHER…OR = ou…ou | NEITHER…NOR = nem…nem | OR SO"]}], "notes": [], "resumo": "💡 RESUMO: OR = ou (alternativa/escolha) | OR = senão/caso contrário (consequência) | EITHER…OR = ou…ou | NEITHER…NOR = nem…nem | OR SO", "module": 2}, {"file": "04_DESPITE_Apesar_De.pdf", "word": "DESPITE / IN SPITE OF", "pt": "APESAR DE", "desc": "Concessão antes de SUBSTANTIVO ou GERÚNDIO — nunca antes de oração com sujeito+verbo", "usos": [{"title": "DESPITE = APESAR DE (antes de substantivo)", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["noun", "Despite the rain, we went out.", "Apesar da chuva, nós saímos."], ["noun", "Despite her age, she runs fast.", "Apesar da idade, ela corre rápido."], ["noun", "Despite the traffic, I arrived on time.", "Apesar do trânsito, cheguei na hora."], ["noun", "He passed despite his difficulties.", "Ele passou apesar das dificuldades."], ["noun", "She smiled despite the pain.", "Ela sorriu apesar da dor."]], "notes": ["⚠️ DESPITE + substantivo/pronome/gerúndio. NUNCA + oração (sujeito + verbo). Para oração use ALTHOUGH."]}, {"title": "IN SPITE OF = APESAR DE (sinônimo de DESPITE, mais formal)", "num": 2, "header": ["Estrutura", "Inglês", "Português"], "rows": [["noun", "In spite of the rain, we went out.", "Apesar da chuva, nós saímos."], ["noun", "In spite of her age, she runs fast.", "Apesar da idade, ela corre rápido."], ["pronoun", "In spite of everything, I still trust him.", "Apesar de tudo, ainda confio nele."], ["gerund", "In spite of being tired, she kept working.", "Apesar de estar cansada, ela continuou trabalhando."]], "notes": ["💡 DESPITE e IN SPITE OF têm o MESMO significado. IN SPITE OF é ligeiramente mais formal e um pouco mais longo."]}, {"title": "DESPITE + gerúndio (-ING)", "num": 3, "header": ["Estrutura", "Inglês", "Português"], "rows": [["gerund", "Despite studying hard, he failed.", "Apesar de estudar muito, ele reprovou."], ["gerund", "Despite being rich, she lives simply.", "Apesar de ser rica, ela vive de forma simples."], ["gerund", "Despite feeling sick, I went to work.", "Apesar de me sentir doente, fui trabalhar."], ["gerund", "Despite trying, I couldn't do it.", "Apesar de tentar, eu não consegui."]], "notes": ["💡 DESPITE + verbo sempre usa a forma -ING (gerúndio). Nunca: 'Despite I studied' ❌ → 'Despite studying' ✅"]}, {"title": "DESPITE / IN SPITE OF vs ALTHOUGH (comparação)", "num": 4, "header": ["Palavra", "O", "que", "vem", "depois", "Exemplo", "Tradução"], "rows": [["DESPITE", "+", "noun/gerund", "", "", "Despite the rain, we went.", "Apesar da chuva, fomos."], ["IN SPITE OF", "+", "noun/gerund", "", "", "In spite of the rain, we went.", "Apesar da chuva, fomos."], ["ALTHOUGH", "+", "oração", "", "", "Although it rained, we went.", "Embora chovesse, fomos."], ["EVEN THOUGH", "+", "oração", "", "", "Even though it rained, we went.", "Mesmo chovendo, fomos."]], "notes": ["⚠️ REGRA FÁCIL: DESPITE/IN SPITE OF + substantivo/gerúndio | ALTHOUGH/EVEN THOUGH + sujeito + verbo."]}, {"title": "DESPITE THE FACT THAT = APESAR DO FATO DE QUE (oração)", "num": 5, "header": ["Estrutura", "Inglês", "Português"], "rows": [["oração", "Despite the fact that it rained, we went out.", "Apesar do fato de que choveu, nós saímos."], ["oração", "Despite the fact that she tried, she failed.", "Apesar do fato de que ela tentou, ela reprovou."], ["oração", "In spite of the fact that he is young, he's responsible.", "Apesar do fato de que é jovem, ele é responsável."], ["oração simples prefira", "ALTHOUGH.", ""]], "notes": ["💡 'DESPITE THE FACT THAT' + oração é a forma de usar DESPITE antes de sujeito + verbo. Mais formal, mais longo.", "🔴 ERRO CLÁSSICO: 'Despite she was tired, she worked.' ❌ — Correto: 'Despite being tired...' ✅ ou 'Although she was tired...' ✅ ou 'Despite the fact that", "✅ she was tired...'", "💡 RESUMO: DESPITE / IN SPITE OF = apesar de (+ substantivo ou gerúndio) | DESPITE THE FACT THAT = apesar do fato de que (+ oração) | Para"]}], "notes": [], "resumo": "💡 RESUMO: DESPITE / IN SPITE OF = apesar de (+ substantivo ou gerúndio) | DESPITE THE FACT THAT = apesar do fato de que (+ oração) | Para", "module": 2}, {"file": "04_SO_Entao_Portanto.pdf", "word": "SO", "pt": "ENTÃO / PORTANTO / TÃO / ASSIM", "desc": "Indica resultado, consequência — ou intensidade de adjetivo/advérbio", "usos": [{"title": "SO = ENTÃO / PORTANTO (resultado/consequência)", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["resultado", "It was raining, so I stayed home.", "Estava chovendo, então fiquei em casa."], ["resultado", "I was hungry, so I ate.", "Eu estava com fome, então comi."], ["resultado", "She studied hard, so she passed.", "Ela estudou muito, então passou."], ["resultado", "He forgot his wallet, so I paid.", "Ele esqueceu a carteira, então eu paguei."], ["resultado", "The traffic was bad, so we were late.", "O trânsito estava ruim, então nos atrasamos."], ["futuro", "I'll be busy tomorrow, so call today.", "Vou estar ocupado amanhã, então ligue hoje."]], "notes": ["💡 SO (conjunção) indica CONSEQUÊNCIA/RESULTADO. A segunda parte é o que acontece POR CAUSA da primeira."]}, {"title": "SO + adjetivo/advérbio = TÃO (intensidade)", "num": 2, "header": ["Estrutura", "Inglês", "Português"], "rows": [["so + adj", "She is so beautiful!", "Ela é tão bonita!"], ["so + adj", "This is so difficult.", "Isso é tão difícil."], ["so + adv", "He runs so fast.", "Ele corre tão rápido."], ["so + much", "I love you so much.", "Eu te amo tanto."], ["so + many", "There are so many people here!", "Tem tanta gente aqui!"], ["so + that", "She was so tired that she slept.", "Ela estava tão cansada que dormiu."]], "notes": ["⚠️ SO + adjetivo = VERY (muito/tão). 'So beautiful' = 'muito bonita'. Mas SO é mais emocional que VERY."]}, {"title": "SO THAT = PARA QUE / A FIM DE QUE (propósito)", "num": 3, "header": ["Contexto", "Inglês", "Português"], "rows": [["propósito", "I study so that I can get a good job.", "Eu estudo para que possa ter um bom emprego."], ["propósito", "Speak slowly so that I understand.", "Fale devagar para que eu entenda."], ["propósito", "Save money so that you can travel.", "Economize dinheiro para que você possa viajar."], ["propósito", "I left early so that I wouldn't be late.", "Saí cedo para não me atrasar."]], "notes": ["💡 SO THAT = 'para que' / 'a fim de que'. Indica PROPÓSITO/INTENÇÃO, não apenas resultado."]}, {"title": "SO como resposta e no discurso (fala)", "num": 4, "header": ["Uso", "Inglês", "Português"], "rows": [["concordância", "— I'm tired. — So am I.", "— Estou cansado. — Eu também."], ["concordância", "— She can swim. — So can he.", "— Ela sabe nadar. — Ele também."], ["início de fala", "So, what do you think?", "Então, o que você acha?"], ["início de fala", "So, let's get started.", "Então, vamos começar."], ["resumo", "So, that's my plan.", "Então, esse é meu plano."], ["hesitação", "So… I don't know how to say this.", "Então… não sei como dizer isso."], ["marcador de discurso.", "", ""]], "notes": ["💡 'So am I / So do I / So can I' = 'eu também'. Muito usado para concordar positivamente. SO no início = marcador de discurso.", "🔴 CONFUSÃO: SO (conjunção = então/portanto) ≠ SO (intensificador = tão/muito). 'It rained so we stayed' (então) vs 'It was SO cold!' (tão).", "💡 RESUMO: SO = então/portanto (resultado) | SO + adj = tão/muito (intensidade) | SO THAT = para que (propósito) | So am I = eu também | SO no início ="]}], "notes": [], "resumo": "💡 RESUMO: SO = então/portanto (resultado) | SO + adj = tão/muito (intensidade) | SO THAT = para que (propósito) | So am I = eu também | SO no início =", "module": 2}, {"file": "05_BECAUSE_Porque.pdf", "word": "BECAUSE", "pt": "PORQUE", "desc": "Explica a CAUSA ou RAZÃO de algo — a palavra mais usada para isso no inglês", "usos": [{"title": "BECAUSE no presente (explicando razões)", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["causa", "I study English because I want a better job.", "Estudo inglês porque quero um emprego melhor."], ["causa", "She is happy because she got good news.", "Ela está feliz porque recebeu boas notícias."], ["causa", "He doesn't eat meat because he is vegetarian.", "Ele não come carne porque é vegetariano."], ["causa", "I like him because he is kind.", "Eu gosto dele porque ele é gentil."], ["causa", "They are late because the traffic is bad.", "Eles estão atrasados porque o trânsito está ruim."], ["causa", "I don't go out because I'm tired.", "Não saio porque estou cansado."]], "notes": ["💡 BECAUSE responde à pergunta WHY (por que). A resposta começa sempre com BECAUSE."]}, {"title": "BECAUSE no passado", "num": 2, "header": ["Estrutura", "Inglês", "Português"], "rows": [["passado", "I stayed home because it was raining.", "Fiquei em casa porque estava chovendo."], ["passado", "She cried because she was sad.", "Ela chorou porque estava triste."], ["passado", "He left early because he had a meeting.", "Ele saiu cedo porque tinha uma reunião."], ["passado", "They didn't come because they were busy.", "Eles não vieram porque estavam ocupados."], ["passado", "I called you because I needed help.", "Liguei para você porque precisava de ajuda."]], "notes": ["🔴 Passado: BECAUSE + sujeito + verbo no passado. Não misture tempos: 'I stayed because it WAS raining' ✅"]}, {"title": "BECAUSE no futuro e em negativas", "num": 3, "header": ["Estrutura", "Inglês", "Português"], "rows": [["futuro", "I will study more because I want to improve.", "Vou estudar mais porque quero melhorar."], ["futuro", "She won't come because she'll be working.", "Ela não vai vir porque vai estar trabalhando."], ["neg. pres.", "I don't watch TV because I prefer reading.", "Não assisto TV porque prefiro ler."], ["neg. perg.", "Why don't you eat? — Because I'm not hungry.", "Por que você não come? — Porque não estou com fome."]], "notes": ["💡 BECAUSE funciona em TODOS os tempos verbais. Sempre explica a razão da ação principal."]}, {"title": "BECAUSE no início da frase (ênfase na razão)", "num": 4, "header": ["Posição", "Inglês", "Português"], "rows": [["início", "Because it was raining, I stayed home.", "Porque estava chovendo, fiquei em casa."], ["início", "Because she studied hard, she passed.", "Porque ela estudou muito, ela passou."], ["início", "Because I was late, I missed the bus.", "Porque eu me atrasei, perdi o ônibus."], ["meio", "I missed the bus because I was late.", "Perdi o ônibus porque me atrasei."]], "notes": ["⚠️ BECAUSE pode vir no início OU no meio da frase. Quando no início, use vírgula depois da primeira oração."]}, {"title": "BECAUSE OF = POR CAUSA DE (antes de substantivo)", "num": 5, "header": ["Estrutura", "Inglês", "Português"], "rows": [["noun", "I stayed home because of the rain.", "Fiquei em casa por causa da chuva."], ["noun", "She was late because of the traffic.", "Ela se atrasou por causa do trânsito."], ["noun", "He left because of a family problem.", "Ele foi embora por causa de um problema de família."], ["pronoun", "It's all because of you.", "É tudo por sua causa."], ["gerund", "I'm tired because of working so much.", "Estou cansado por causa de trabalhar muito."]], "notes": ["⚠️ BECAUSE + oração (sujeito + verbo) | BECAUSE OF + substantivo/pronome. 'Because it rained' vs 'Because of the rain'."]}, {"title": "BECAUSE vs SINCE vs AS (todos = porque, mas diferentes)", "num": 6, "header": ["Palavra", "Registro", "Uso", "Exemplo"], "rows": [["BECAUSE", "neutro", "principal razão", "I left because I was tired."], ["SINCE", "formal", "razão já conhecida", "Since you're here, let's start."], ["AS", "formal", "razão simultânea", "As it was raining, we stayed."], ["FOR", "literário", "razão explicativa", "She rested, for she was ill."]], "notes": ["💡 Na prática: BECAUSE é sempre seguro. SINCE e AS são mais formais e implicam que a razão já é conhecida pelo ouvinte.", "🔴 ERRO CLÁSSICO: 'The reason is because…' ❌ — redundante. O correto é 'The reason is THAT…' ✅ ou simplesmente 'I did it because…' ✅", "💡 RESUMO: BECAUSE + oração = porque (razão principal) | BECAUSE OF + substantivo = por causa de | BECAUSE responde à pergunta WHY."]}], "notes": ["∵"], "resumo": "💡 RESUMO: BECAUSE + oração = porque (razão principal) | BECAUSE OF + substantivo = por causa de | BECAUSE responde à pergunta WHY.", "module": 2}, {"file": "05_UNLESS_A_Menos_Que.pdf", "word": "UNLESS", "pt": "A MENOS QUE / SE NÃO", "desc": "Condição negativa — equivale a IF…NOT. Introduz a única exceção.", "usos": [{"title": "UNLESS = A MENOS QUE / SE NÃO", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["unless", "Unless you study, you'll fail.", "A menos que você estude, vai reprovar."], ["unless", "I'll go unless it rains.", "Vou ir a menos que chova."], ["unless", "Unless she calls, don't wait for her.", "A menos que ela ligue, não a espere."], ["unless", "I won't go unless you come too.", "Não vou a menos que você venha também."], ["unless", "Unless you hurry, we'll be late.", "Se você não se apressar, vamos nos atrasar."]], "notes": ["⚠️ UNLESS = IF…NOT. 'Unless you study' = 'If you don't study'. Depois de UNLESS usa-se PRESENTE SIMPLES (não will)."]}, {"title": "UNLESS vs IF…NOT (comparação)", "num": 2, "header": ["Estrutura", "Inglês", "com", "UNLESS", "Inglês", "com", "IF…NOT"], "rows": [["mesma ideia", "Unless", "you", "call, I'll leave.", "If you", "don't", "call, I'll leave."], ["mesma ideia", "Unless", "it rains,", "we'll go out.", "If it doesn't", "", "rain, we'll go out."], ["mesma ideia", "Unless", "she", "helps, we'll fail.", "If she", "doesn't", "help, we'll fail."], ["mesma ideia", "Don't", "go unless", "I say so.", "Don't", "go if", "I don't say so."]], "notes": ["💡 UNLESS e IF…NOT têm o mesmo significado. UNLESS é mais direto e elegante — evita repetir 'not'."]}, {"title": "UNLESS em situações do dia a dia", "num": 3, "header": ["Contexto", "Inglês", "Português"], "rows": [["aviso", "Don't call me unless it's urgent.", "Não me ligue a menos que seja urgente."], ["regra", "Unless stated otherwise, the rule applies.", "A menos que indicado o contrário, a regra se aplica."], ["oferta", "I'll do it unless you prefer to.", "Farei isso a menos que você prefira fazer."], ["permissão", "Unless you have a ticket, you can't enter.", "A menos que tenha ingresso, você não pode entrar."]], "notes": ["💡 UNLESS é muito usado para dar regras, avisos e exceções. 'Unless stated otherwise' é expressão muito usada em documentos.", "🔴 ERRO COMUM: 'Unless you won't call, I'll leave.' ❌ — UNLESS já tem sentido negativo, não adicione NOT: 'Unless you call, I'll leave.' ✅", "💡 RESUMO: UNLESS = a menos que / se não (= IF…NOT) | UNLESS + presente simples | Nunca UNLESS + will | Nunca UNLESS + NOT junto."]}], "notes": [], "resumo": "💡 RESUMO: UNLESS = a menos que / se não (= IF…NOT) | UNLESS + presente simples | Nunca UNLESS + will | Nunca UNLESS + NOT junto.", "module": 2}, {"file": "06_IF_Se_Condicao.pdf", "word": "IF", "pt": "SE", "desc": "Condicional — introduz uma situação hipotética ou possível", "usos": [{"title": "IF real (situação possível no presente/futuro)", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["if + pres / will", "If it rains, I'll stay home.", "Se chover, fico em casa."], ["if + pres / will", "If you study, you'll pass.", "Se você estudar, você vai passar."], ["if + pres / will", "If she calls, tell her I'm busy.", "Se ela ligar, diz que estou ocupado."], ["if + pres / will", "I'll go if you go.", "Vou se você for."], ["if + pres / will", "If he is late, we'll start without him.", "Se ele atrasar, começamos sem ele."]], "notes": ["⚠️ Depois de IF no futuro usa-se PRESENTE SIMPLES (não will): 'If it RAINS' ✅ / 'If it WILL rain' ❌"]}, {"title": "IF em perguntas indiretas (se = whether)", "num": 2, "header": ["Estrutura", "Inglês", "Português"], "rows": [["pergunta indireta", "I don't know if she's coming.", "Não sei se ela vem."], ["pergunta indireta", "Can you check if the door is locked?", "Você pode verificar se a porta está trancada?"], ["pergunta indireta", "Tell me if you need help.", "Me diga se você precisar de ajuda."], ["pergunta indireta", "I wonder if he knows.", "Fico me perguntando se ele sabe."]], "notes": ["💡 IF em pergunta indireta = WHETHER. 'I don't know if/whether she's coming.' — os dois são corretos."]}, {"title": "IF em outros contextos do dia a dia", "num": 3, "header": ["Uso", "Inglês", "Português"], "rows": [["polidez", "I'd be grateful if you could help.", "Ficaria grato se você pudesse ajudar."], ["polidez", "If you don't mind, I'll sit here.", "Se não se importar, vou sentar aqui."], ["surpresa", "If that's true, I'm shocked.", "Se isso for verdade, estou chocado."], ["condição", "Only if you promise.", "Só se você prometer."], ["oferta", "If you want, I can help.", "Se você quiser, posso ajudar."]], "notes": ["💡 IF é um dos conectivos mais usados no inglês. Aparece em pedidos educados, condições, ofertas e perguntas indiretas.", "🔴 ERRO CLÁSSICO: 'If it will rain, I'll stay home.' ❌ — Depois de IF condicionalmente, usa-se PRESENTE: 'If it RAINS, I'll stay.' ✅", "💡 RESUMO: IF = se (condição real) | IF = se (pergunta indireta) | IF + presente / resultado com WILL | ONLY IF = só se | IF YOU WANT = se quiser."]}], "notes": [], "resumo": "💡 RESUMO: IF = se (condição real) | IF = se (pergunta indireta) | IF + presente / resultado com WILL | ONLY IF = só se | IF YOU WANT = se quiser.", "module": 2}, {"file": "06_THEREFORE_Portanto.pdf", "word": "THEREFORE", "pt": "PORTANTO / POR ISSO / LOGO", "desc": "Indica RESULTADO ou CONCLUSÃO lógica — mais formal que SO", "usos": [{"title": "THEREFORE = PORTANTO / POR ISSO (resultado lógico)", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["resultado", "She studied hard. Therefore, she passed.", "Ela estudou muito. Portanto, ela passou."], ["resultado", "It was raining. Therefore, we stayed home.", "Estava chovendo. Portanto, ficamos em casa."], ["resultado", "He was sick. Therefore, he didn't go to work.", "Ele estava doente. Por isso, não foi trabalhar."], ["resultado", "The price increased. Therefore, sales dropped.", "O preço aumentou. Portanto, as vendas caíram."], ["resultado", "I forgot my wallet. Therefore, I can't pay.", "Esqueci a carteira. Por isso, não posso pagar."]], "notes": ["💡 THEREFORE é mais FORMAL que SO. Pode vir no início da segunda frase ou no meio, entre vírgulas."]}, {"title": "Posições do THEREFORE na frase", "num": 2, "header": ["Posição", "Inglês", "Português"], "rows": [["início da frase", "It rained. Therefore, we stayed home.", "Choveu. Portanto, ficamos em casa."], ["meio (entre vírgulas)", "It rained. We, therefore, stayed home.", "Choveu. Ficamos, portanto, em casa."], ["após ponto e vírgula", "It rained; therefore, we stayed home.", "Choveu; portanto, ficamos em casa."]], "notes": ["⚠️ THEREFORE é sempre separado por vírgulas quando no meio da frase. Nunca une diretamente duas orações sem pontuação."]}, {"title": "THEREFORE vs SO vs CONSEQUENTLY", "num": 3, "header": ["Palavra", "Registro", "Uso", "Exemplo"], "rows": [["SO", "informal/neutro", "resultado casual", "It rained, so we stayed."], ["THEREFORE", "formal", "conclusão lógica", "It rained. Therefore, we stayed."], ["CONSEQUENTLY", "muito formal", "consequência séria", "It rained. Consequently, we stayed."], ["THUS", "literário", "conclusão técnica", "It rained; thus, we stayed."], ["HENCE", "técnico", "por essa razão", "The data is clear, hence our decision."]], "notes": ["💡 Na fala do dia a dia: SO. Em e-mails formais/trabalho: THEREFORE. Em textos acadêmicos: CONSEQUENTLY / THUS."]}, {"title": "THEREFORE em diferentes tempos verbais", "num": 4, "header": ["Tempo", "Inglês", "Português"], "rows": [["presente", "She is qualified. Therefore, she gets the job.", "Ela é qualificada. Portanto, ela fica com o emprego."], ["passado", "He worked hard. Therefore, he got promoted.", "Ele trabalhou muito. Por isso, foi promovido."], ["futuro", "We prepared well. Therefore, we will succeed.", "Nos preparamos bem. Portanto, vamos ter sucesso."], ["negativo", "She didn't study. Therefore, she failed.", "Ela não estudou. Por isso, reprovou."]], "notes": ["💡 THEREFORE funciona com qualquer tempo verbal — sempre indica que a segunda parte é consequência lógica da primeira.", "🔴 ❌ ✅ ✅ ERRO COMUM: 'It rained therefore we stayed.' — precisa de pontuação: 'It rained. Therefore, we stayed.' ou 'It rained; therefore, we stayed.'", "💡 RESUMO: THEREFORE = portanto / por isso / logo (resultado formal) | Sempre com vírgula | Mais formal que SO | Equivale a: consequently, thus, hence."]}], "notes": [], "resumo": "💡 RESUMO: THEREFORE = portanto / por isso / logo (resultado formal) | Sempre com vírgula | Mais formal que SO | Equivale a: consequently, thus, hence.", "module": 2}, {"file": "07_ALSO_TOO_Tambem.pdf", "word": "ALSO / TOO / AS WELL", "pt": "TAMBÉM", "desc": "Adicionam informação — mesma ideia, posições diferentes na frase", "usos": [{"title": "ALSO = TAMBÉM (meio da frase, mais formal)", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["meio", "She speaks English. She also speaks Spanish.", "Ela fala inglês. Ela também fala espanhol."], ["meio", "I like coffee. I also like tea.", "Eu gosto de café. Eu também gosto de chá."], ["meio", "He is smart. He is also very kind.", "Ele é inteligente. Ele também é muito gentil."], ["meio", "We have food. We also have drinks.", "Temos comida. Também temos bebidas."], ["negativa", "She doesn't smoke. She also doesn't drink.", "Ela não fuma. Ela também não bebe."]], "notes": ["💡 ALSO fica no MEIO da frase, geralmente antes do verbo principal (ou depois do auxiliar/verbo 'to be')."]}, {"title": "TOO = TAMBÉM (final de frase, informal)", "num": 2, "header": ["Estrutura", "Inglês", "Português"], "rows": [["fim", "I like coffee. I like tea, too.", "Gosto de café. Gosto de chá também."], ["fim", "She is smart. She is kind, too.", "Ela é inteligente. É gentil também."], ["fim", "— I'm tired. — Me too!", "— Estou cansado. — Eu também!"], ["fim", "He can swim. He can dance, too.", "Ele sabe nadar. Sabe dançar também."], ["fim", "I'll come. She'll come, too.", "Eu vou. Ela também vai."]], "notes": ["⚠️ TOO fica sempre no FINAL da frase ou oração. 'Me too!' é a resposta mais usada para concordar com algo positivo."]}, {"title": "AS WELL = TAMBÉM (final de frase, neutro/formal)", "num": 3, "header": ["Estrutura", "Inglês", "Português"], "rows": [["fim", "She speaks French as well.", "Ela fala francês também."], ["fim", "I'll bring food as well.", "Vou trazer comida também."], ["fim", "They invited her as well.", "Eles a convidaram também."], ["fim", "He works and studies as well.", "Ele trabalha e estuda também."]], "notes": ["💡 AS WELL = TOO em posição e significado. AS WELL é ligeiramente mais formal e mais comum no inglês britânico."]}, {"title": "ALSO / TOO / AS WELL: comparação de posição", "num": 4, "header": ["Palavra", "Posição", "Registro", "Exemplo"], "rows": [["ALSO", "meio da frase", "neutro/formal", "She also speaks French."], ["TOO", "final da frase", "informal", "She speaks French, too."], ["AS WELL", "final da frase", "neutro/formal", "She speaks French as well."]], "notes": ["💡 REGRA FÁCIL: ALSO = meio | TOO e AS WELL = final. Na fala casual: TOO. Em e-mails e textos: ALSO ou AS WELL."]}, {"title": "EITHER = TAMBÉM (em frases negativas)", "num": 5, "header": ["Estrutura", "Inglês", "Português"], "rows": [["neg. + either", "I don't like coffee. I don't like tea, either.", "Não gosto de café. Também não gosto de chá."], ["neg. + either", "She didn't come. He didn't come, either.", "Ela não veio. Ele também não veio."], ["Me either", "— I don't like it. — Me neither / either!", "— Não gosto. — Eu também não!"]], "notes": ["⚠️ Em frases NEGATIVAS: use EITHER (não TOO ou AS WELL). 'Me neither' = 'Me either' = 'Eu também não.' — ambos corretos!", "🔴 ❌ ✅ ❌ ERRO COMUM: 'I also don't like it.' (negativa) — Em negativas, use EITHER: 'I don't like it either.' | 'She too doesn't smoke.' — TOO não fica no", "meio: 'She doesn't smoke either.' ✅", "💡 RESUMO: ALSO = também (meio, neutro) | TOO = também (final, informal) | AS WELL = também (final, formal) | EITHER = também não (negativas)."]}], "notes": [], "resumo": "💡 RESUMO: ALSO = também (meio, neutro) | TOO = também (final, informal) | AS WELL = também (final, formal) | EITHER = também não (negativas).", "module": 2}, {"file": "07_WHEN_WHILE_Quando_Enquanto.pdf", "word": "WHEN / WHILE / AS", "pt": "QUANDO / ENQUANTO", "desc": "Conectivos de tempo que indicam simultaneidade ou momento de uma ação", "usos": [{"title": "WHEN = QUANDO (num momento específico)", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["momento", "When I arrived, she was cooking.", "Quando eu cheguei, ela estava cozinhando."], ["momento", "Call me when you get home.", "Me ligue quando você chegar em casa."], ["momento", "When the phone rang, I was sleeping.", "Quando o telefone tocou, eu estava dormindo."], ["hábito", "When I was young, I played soccer every day.", "Quando eu era jovem, jogava futebol todo dia."], ["futuro", "I'll tell you when I know the answer.", "Vou te dizer quando eu souber a resposta."]], "notes": ["💡 WHEN = num momento específico. A ação principal acontece NESSE momento ou logo depois."]}, {"title": "WHILE = ENQUANTO (duas ações ao mesmo tempo)", "num": 2, "header": ["Estrutura", "Inglês", "Português"], "rows": [["simultâneo", "I listened to music while I cooked.", "Ouvi música enquanto cozinhava."], ["simultâneo", "She called me while I was working.", "Ela me ligou enquanto eu trabalhava."], ["simultâneo", "While he studied, she watched TV.", "Enquanto ele estudava, ela assistia TV."], ["simultâneo", "I fell asleep while I was reading.", "Adormeci enquanto estava lendo."], ["simultâneo", "While you were out, I cleaned the house.", "Enquanto você estava fora, eu limpei a casa."]], "notes": ["⚠️ WHILE indica duas ações SIMULTÂNEAS. Frequentemente acompanha o passado contínuo (was/were + -ing)."]}, {"title": "AS = ENQUANTO / À MEDIDA QUE (processo simultâneo)", "num": 3, "header": ["Estrutura", "Inglês", "Português"], "rows": [["simultâneo", "As I walked home, it started to rain.", "Enquanto eu caminhava para casa, começou a chover."], ["processo", "As she got older, she became wiser.", "À medida que ela envelheceu, ficou mais sábia."], ["processo", "The music got louder as we entered.", "A música ficou mais alta à medida que entramos."], ["simultâneo", "As he left, she started crying.", "Enquanto ele saía, ela começou a chorar."]], "notes": ["💡 AS de tempo = processo gradual ou duas ações acontecendo JUNTAS. Mais literário/formal que WHILE."]}, {"title": "WHEN vs WHILE vs AS (comparação)", "num": 4, "header": ["Palavra", "Ênfase", "Exemplo", "Tradução"], "rows": [["WHEN", "momento pontual", "When she arrived, he left.", "Quando ela chegou, ele foi."], ["WHILE", "duração simultânea", "While she cooked, he cleaned.", "Enquanto ela cozinhava, ele limpava."], ["AS", "processo gradual", "As she grew up, she changed.", "À medida que cresceu, ela mudou."]], "notes": ["💡 WHEN = ponto no tempo | WHILE = período simultâneo | AS = gradual ou literário.", "🔴 ❌ ✅ ERRO COMUM: 'When I will arrive, I'll call you.' — Depois de WHEN de futuro, usa-se presente simples: 'When I ARRIVE, I'll call you.'", "💡 RESUMO: WHEN = quando (momento) | WHILE = enquanto (simultâneo, com duração) | AS = enquanto/à medida que (processo ou literário)."]}], "notes": [], "resumo": "💡 RESUMO: WHEN = quando (momento) | WHILE = enquanto (simultâneo, com duração) | AS = enquanto/à medida que (processo ou literário).", "module": 2}, {"file": "08_BEFORE_AFTER_Antes_Depois.pdf", "word": "BEFORE / AFTER", "pt": "ANTES DE / DEPOIS DE", "desc": "Indicam sequência temporal — o que vem antes e o que vem depois", "usos": [{"title": "BEFORE = ANTES DE / ANTES QUE", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["oração", "Brush your teeth before you go to bed.", "Escove os dentes antes de ir para a cama."], ["oração", "Before I left, I turned off the lights.", "Antes de sair, apaguei as luzes."], ["oração", "Think before you speak.", "Pense antes de falar."], ["noun", "I need to finish before dinner.", "Preciso terminar antes do jantar."], ["gerund", "Before leaving, check the door.", "Antes de sair, verifique a porta."]], "notes": ["💡 BEFORE + oração (sujeito + verbo) ou BEFORE + substantivo ou BEFORE + gerúndio (-ing)."]}, {"title": "AFTER = DEPOIS DE / APÓS", "num": 2, "header": ["Estrutura", "Inglês", "Português"], "rows": [["oração", "After she finished work, she went to the gym.", "Depois que ela terminou o trabalho, foi à academia."], ["oração", "I felt better after I slept.", "Me senti melhor depois que dormi."], ["oração", "Call me after you arrive.", "Me ligue depois que você chegar."], ["noun", "After dinner, we watched a movie.", "Depois do jantar, assistimos um filme."], ["gerund", "After eating, she went for a walk.", "Depois de comer, ela foi caminhar."]], "notes": ["⚠️ AFTER + oração ou AFTER + noun ou AFTER + gerúndio. No futuro, usa presente simples depois de AFTER: 'After you ARRIVE...' ✅"]}, {"title": "BEFORE / AFTER como preposições (antes de noun)", "num": 3, "header": ["Palavra", "Inglês", "Português"], "rows": [["BEFORE + noun", "Before the meeting, read the report.", "Antes da reunião, leia o relatório."], ["BEFORE + noun", "I'll be there before noon.", "Estarei lá antes do meio-dia."], ["AFTER + noun", "After the class, let's have coffee.", "Depois da aula, vamos tomar café."], ["AFTER + noun", "She left after the show.", "Ela foi embora depois do show."]], "notes": ["💡 BEFORE/AFTER + substantivo = preposição. BEFORE/AFTER + oração = conjunção. Mesma palavra, dois papéis!"]}, {"title": "BEFORE / AFTER em expressões do dia a dia", "num": 4, "header": ["Expressão", "Inglês", "Português"], "rows": [["long before", "I knew it long before you told me.", "Eu sabia muito antes de você me dizer."], ["right after", "Right after dinner, he called.", "Logo depois do jantar, ele ligou."], ["just before", "Just before leaving, she smiled.", "Logo antes de sair, ela sorriu."], ["the day before", "The day before the trip, we packed.", "No dia anterior à viagem, arrumamos as malas."], ["the day after", "The day after, everything changed.", "No dia seguinte, tudo mudou."], ["BEFORE/AFTER.", "", ""]], "notes": ["💡 'Right after' = logo depois | 'Just before' = logo antes | 'Long before' = muito antes | Muito usadas no dia a dia.", "🔴 ERRO COMUM: 'After I will eat, I will sleep.' ❌ — Depois de AFTER/BEFORE no futuro, usa-se PRESENTE SIMPLES: 'After I EAT, I will sleep.' ✅", "💡 RESUMO: BEFORE = antes de (+ oração, noun ou gerúndio) | AFTER = depois de (+ oração, noun ou gerúndio) | No futuro: presente simples após"]}], "notes": [], "resumo": "💡 RESUMO: BEFORE = antes de (+ oração, noun ou gerúndio) | AFTER = depois de (+ oração, noun ou gerúndio) | No futuro: presente simples após", "module": 2}, {"file": "08_IN_ADDITION_Alem_Disso.pdf", "word": "IN ADDITION / MOREOVER / FURTHERMORE", "pt": "ALÉM", "desc": "DISSO / ADEMAIS", "usos": [{"title": "IN ADDITION = ALÉM DISSO (acréscimo neutro/formal)", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["acréscimo", "The hotel is comfortable. In addition, it's cheap.", "O hotel é confortável. Além disso, é barato."], ["acréscimo", "She is experienced. In addition, she works fast.", "Ela é experiente. Além disso, trabalha rápido."], ["acréscimo", "The plan saves money. In addition, it saves time.", "O plano economiza dinheiro. Além disso, economiza tempo."], ["acréscimo", "He speaks English. In addition, he speaks French.", "Ele fala inglês. Além disso, fala francês."]], "notes": ["💡 IN ADDITION sempre inicia a segunda frase com vírgula. Equivale a 'besides' mas é mais neutro e formal."]}, {"title": "IN ADDITION TO = ALÉM DE (antes de substantivo/gerúndio)", "num": 2, "header": ["Estrutura", "Inglês", "Português"], "rows": [["+ noun", "In addition to English, she speaks French.", "Além do inglês, ela fala francês."], ["+ noun", "In addition to the salary, he gets bonuses.", "Além do salário, ele recebe bônus."], ["+ gerund", "In addition to working, she studies at night.", "Além de trabalhar, ela estuda à noite."], ["+ gerund", "In addition to cooking, he cleans the house.", "Além de cozinhar, ele limpa a casa."]], "notes": ["⚠️ IN ADDITION TO + substantivo/gerúndio (como 'besides' e 'apart from'). IN ADDITION (sem TO) + oração."]}, {"title": "MOREOVER = ALÉM DISSO / ADEMAIS (acréscimo enfático)", "num": 3, "header": ["Estrutura", "Inglês", "Português"], "rows": [["ênfase", "The plan is efficient. Moreover, it's affordable.", "O plano é eficiente. Além disso, é acessível."], ["ênfase", "She is talented. Moreover, she is very dedicated.", "Ela é talentosa. Além disso, é muito dedicada."], ["ênfase", "The product is good. Moreover, it comes with a warranty.", "O produto é bom. Além disso, vem com garantia."]], "notes": ["💡 MOREOVER acrescenta um ponto ainda MAIS IMPORTANTE ou surpreendente do que o anterior. Mais formal que IN ADDITION."]}, {"title": "FURTHERMORE = ALÉM DISSO (acréscimo em argumento formal)", "num": 4, "header": ["Estrutura", "Inglês", "Português"], "rows": [["formal", "The data shows growth. Furthermore, profits increased.", "Os dados mostram crescimento. Além disso, os lucros aumentaram."], ["formal", "The policy is fair. Furthermore, it's effective.", "A política é justa. Além disso, é eficaz."], ["formal", "He is qualified. Furthermore, he has great experience.", "Ele é qualificado. Além disso, tem ótima experiência."]], "notes": ["💡 FURTHERMORE é muito formal — típico de textos acadêmicos, relatórios e argumentações formais. Na fala: ALSO ou BESIDES."]}, {"title": "Comparação de formalidade: ALSO / IN ADDITION / MOREOVER / FURTHERMORE", "num": 5, "header": ["Palavra", "Registro", "Posição", "Exemplo", "rápido"], "rows": [["ALSO", "casual/neutro", "meio da frase", "She also", "speaks French."], ["BESIDES", "informal", "início da frase", "Besides,", "it's too expensive."], ["IN ADDITION", "neutro/formal", "início da frase", "In addition,", "it's cheap."], ["MOREOVER", "formal", "início da frase", "Moreover,", "it's affordable."], ["FURTHERMORE", "muito formal", "início da frase", "Furthermore,", "profits rose."], ["FURTHERMORE são para escrita formal.", "", "", "", ""], ["disso (muito formal) | IN ADDITION TO", "+ noun/gerund.", "", "", ""]], "notes": ["💡 Escada de formalidade: ALSO → BESIDES → IN ADDITION → MOREOVER → FURTHERMORE. Use de acordo com o contexto.", "🔴 ERRO COMUM: usar MOREOVER e FURTHERMORE na fala informal — soa artificial. Na conversa: 'also', 'and', 'plus', 'on top of that'. MOREOVER e", "💡 RESUMO: ALSO = também (meio, neutro) | IN ADDITION = além disso (neutro-formal) | MOREOVER = além disso (enfático) | FURTHERMORE = além"]}], "notes": [], "resumo": "💡 RESUMO: ALSO = também (meio, neutro) | IN ADDITION = além disso (neutro-formal) | MOREOVER = além disso (enfático) | FURTHERMORE = além", "module": 2}, {"file": "09_AS_A_RESULT_Como_Resultado.pdf", "word": "AS A RESULT / CONSEQUENTLY", "pt": "COMO RESULTADO /", "desc": "CONSEQUENTEMENTE", "usos": [{"title": "AS A RESULT = COMO RESULTADO / POR ISSO", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["resultado", "She trained every day. As a result, she won.", "Ela treinou todo dia. Como resultado, ela ganhou."], ["resultado", "The system crashed. As a result, we lost data.", "O sistema travou. Como resultado, perdemos dados."], ["resultado", "He didn't sleep. As a result, he was tired all day.", "Ele não dormiu. Por isso, ficou cansado o dia todo."], ["resultado", "Prices rose. As a result, people bought less.", "Os preços subiram. Como resultado, as pessoas compraram menos."], ["resultado", "She practiced daily. As a result, she improved fast.", "Ela praticou diariamente. Como resultado, melhorou rápido."]], "notes": ["💡 AS A RESULT sempre inicia a SEGUNDA frase, indicando o que aconteceu POR CAUSA da primeira."]}, {"title": "CONSEQUENTLY = CONSEQUENTEMENTE (mais formal)", "num": 2, "header": ["Estrutura", "Inglês", "Português"], "rows": [["formal", "The budget was cut. Consequently, staff were laid off.", "O orçamento foi cortado. Consequentemente, funcionários foram"], ["", "", "demitidos."], ["formal", "He missed the deadline. Consequently, he lost the", "Ele perdeu o prazo. Consequentemente, perdeu o contrato."], ["", "contract.", ""], ["formal", "The road was blocked. Consequently, traffic was", "A estrada foi bloqueada. Consequentemente, o trânsito foi desviado."], ["", "diverted.", ""], ["formal", "She failed the test. Consequently, she had to repeat the", "Ela reprovou no teste. Consequentemente, teve que repetir o ano."], ["", "year.", ""]], "notes": ["⚠️ CONSEQUENTLY é muito formal — use em e-mails profissionais, textos acadêmicos, relatórios. Na fala, prefira SO ou AS A RESULT."]}, {"title": "AS A RESULT OF = COMO RESULTADO DE (antes de substantivo)", "num": 3, "header": ["Estrutura", "Inglês", "Português"], "rows": [["noun", "As a result of the rain, the game was cancelled.", "Como resultado da chuva, o jogo foi cancelado."], ["noun", "As a result of his hard work, he got promoted.", "Como resultado do seu trabalho duro, ele foi promovido."], ["noun", "As a result of the accident, the road was closed.", "Como resultado do acidente, a estrada foi fechada."], ["gerund", "As a result of studying hard, she passed.", "Como resultado de estudar muito, ela passou."]], "notes": ["💡 AS A RESULT OF + substantivo/gerúndio. Equivale a 'because of' mas com ênfase no resultado, não na causa."]}, {"title": "Comparação prática: SO / THEREFORE / AS A RESULT / CONSEQUENTLY", "num": 4, "header": ["Palavra", "Registro", "Exemplo", "rápido", "Tradução"], "rows": [["SO", "casual/fala", "It rained,", "so we stayed.", "Choveu, então ficamos."], ["THEREFORE", "formal", "It rained.", "Therefore, we stayed.", "Choveu. Portanto, ficamos."], ["AS A RESULT", "formal/neutro", "It rained.", "As a result, we stayed.", "Choveu. Como resultado, ficamos."], ["CONSEQUENTLY", "muito formal", "It rained.", "Consequently, we stayed.", "Choveu. Consequentemente, ficamos."], ["THUS", "técnico", "It rained;", "thus, we stayed.", "Choveu; assim, ficamos."], ["resultado de | Use SO na fala,", "THEREFORE ou AS", "A RESULT", "em e-mails.", ""]], "notes": ["💡 Todos indicam o mesmo resultado — a diferença é o NÍVEL DE FORMALIDADE. SO para conversa, CONSEQUENTLY para relatórios.", "🔴 ERRO COMUM: usar CONSEQUENTLY na fala: 'It rained. Consequently, we stayed.' — soa artificial. Na fala: 'It rained, SO we stayed.' ✅", "💡 RESUMO: AS A RESULT = como resultado (neutro-formal) | CONSEQUENTLY = consequentemente (muito formal) | AS A RESULT OF + noun = como"]}], "notes": [], "resumo": "💡 RESUMO: AS A RESULT = como resultado (neutro-formal) | CONSEQUENTLY = consequentemente (muito formal) | AS A RESULT OF + noun = como", "module": 2}, {"file": "09_HOWEVER_No_Entanto.pdf", "word": "HOWEVER", "pt": "NO ENTANTO / PORÉM / MAS", "desc": "Contraste formal entre duas ideias — mais forte e formal que BUT", "usos": [{"title": "HOWEVER = NO ENTANTO (contraste entre frases)", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["contraste", "She studied hard. However, she failed the test.", "Ela estudou muito. No entanto, reprovou."], ["contraste", "The plan sounds good. However, it's expensive.", "O plano parece bom. No entanto, é caro."], ["contraste", "He is young. However, he is very experienced.", "Ele é jovem. No entanto, é muito experiente."], ["contraste", "I was tired. However, I finished the project.", "Eu estava cansado. No entanto, terminei o projeto."], ["contraste", "The movie was long. However, it was worth watching.", "O filme era longo. No entanto, valia a pena assistir."]], "notes": ["💡 HOWEVER sempre separa duas frases completas com ponto ou ponto e vírgula. Nunca une duas orações diretamente como BUT."]}, {"title": "Posições do HOWEVER na frase", "num": 2, "header": ["Posição", "Inglês", "Português"], "rows": [["início + vírgula", "It was cold. However, we went out.", "Estava frio. No entanto, saímos."], ["meio + vírgulas", "It was cold. We, however, went out.", "Estava frio. Nós, no entanto, saímos."], ["após ponto e vírgula", "It was cold; however, we went out.", "Estava frio; no entanto, saímos."]], "notes": ["⚠️ HOWEVER precisa de pontuação ao redor. No início: vírgula depois. No meio: vírgulas dos dois lados. Nunca sem pontuação."]}, {"title": "HOWEVER vs BUT (diferença prática)", "num": 3, "header": ["Palavra", "Registro", "Estrutura", "Exemplo"], "rows": [["BUT", "informal/neutro", "une duas orações", "It was cold, but we went out."], ["HOWEVER", "formal", "separa duas frases", "It was cold. However, we went out."], ["BUT", "fala casual", "pode iniciar frase", "But we went out anyway!"], ["HOWEVER", "escrita formal", "início com vírgula", "However, we went out."]], "notes": ["💡 Na fala do dia a dia: BUT. Em e-mails profissionais, textos e apresentações: HOWEVER. O significado é o mesmo."]}, {"title": "HOWEVER = DE QUALQUER FORMA QUE (modo)", "num": 4, "header": ["Contexto", "Inglês", "Português"], "rows": [["modo", "However you do it, be careful.", "De qualquer forma que você faça, seja cuidadoso."], ["modo", "However hard it is, don't give up.", "Por mais difícil que seja, não desista."], ["modo", "However much you eat, you stay thin.", "Por mais que você coma, você continua magro."], ["modo", "However fast he runs, I'll catch him.", "Por mais rápido que ele corra, eu o pego."], ["redor.", "", ""]], "notes": ["💡 HOWEVER + adjetivo/advérbio = 'por mais que / de qualquer forma que'. Esse uso é diferente do contraste!", "🔴 ERRO COMUM: 'She studied hard, however she failed.' ❌ — não pode unir duas orações só com vírgula. Use: 'She studied hard. However, she failed.'", "✅ ✅ ou 'She studied hard; however, she failed.'", "💡 RESUMO: HOWEVER = no entanto/porém (contraste formal, frases separadas) | HOWEVER + adj = por mais que (modo) | Sempre com pontuação ao"]}], "notes": [], "resumo": "💡 RESUMO: HOWEVER = no entanto/porém (contraste formal, frases separadas) | HOWEVER + adj = por mais que (modo) | Sempre com pontuação ao", "module": 2}, {"file": "10_ALTHOUGH_Embora_Mesmo_Que.pdf", "word": "ALTHOUGH / EVEN THOUGH / THOUGH", "pt": "EMBORA /", "desc": "MESMO QUE / APESAR DE QUE", "usos": [{"title": "ALTHOUGH = EMBORA / APESAR DE QUE", "num": 1, "header": ["Estrutura", "Inglês", "Português"], "rows": [["concessão", "Although it was raining, we went out.", "Embora estivesse chovendo, nós saímos."], ["concessão", "Although she was tired, she kept working.", "Embora estivesse cansada, ela continuou trabalhando."], ["concessão", "Although he is young, he is very responsible.", "Embora seja jovem, ele é muito responsável."], ["concessão", "I enjoyed the trip, although it was expensive.", "Eu curtei a viagem, embora fosse cara."], ["concessão", "Although I don't like coffee, I drink it.", "Embora eu não goste de café, eu o bebo."]], "notes": ["💡 ALTHOUGH pode vir no INÍCIO ou no MEIO da frase. Quando no início, geralmente tem vírgula separando as duas partes."]}, {"title": "EVEN THOUGH = MESMO QUE / MESMO ASSIM (ênfase maior)", "num": 2, "header": ["Estrutura", "Inglês", "Português"], "rows": [["ênfase", "Even though it was freezing, she wore a t-shirt.", "Mesmo com frio intenso, ela usou camiseta."], ["ênfase", "Even though he studied, he failed.", "Mesmo tendo estudado, ele reprovou."], ["ênfase", "I love her even though she's difficult.", "Eu a amo mesmo ela sendo difícil."], ["ênfase", "Even though I'm tired, I'll finish this.", "Mesmo cansado, vou terminar isso."], ["ênfase", "He came even though nobody invited him.", "Ele veio mesmo sem ninguém tê-lo convidado."]], "notes": ["⚠️ EVEN THOUGH é mais enfático que ALTHOUGH — indica um contraste ainda mais surpreendente ou forte."]}, {"title": "THOUGH = EMBORA / MAS (informal, final de frase)", "num": 3, "header": ["Posição", "Inglês", "Português"], "rows": [["início", "Though it was late, she called me.", "Embora fosse tarde, ela me ligou."], ["meio", "I liked the food. The price, though, was high.", "Eu gostei da comida. O preço, porém, estava alto."], ["fim", "The food was good. Expensive, though.", "A comida estava boa. Cara, porém."], ["fim", "I'll go. I'm not happy about it, though.", "Vou ir. Não estou feliz com isso, porém."]], "notes": ["💡 THOUGH informal pode vir no FINAL da frase (ALTHOUGH e EVEN THOUGH não podem). 'It was good, though.' = 'Foi bom, porém.'"]}, {"title": "ALTHOUGH vs EVEN THOUGH vs THOUGH", "num": 4, "header": ["Palavra", "Força", "Posição", "Exemplo"], "rows": [["ALTHOUGH", "neutra", "início / meio", "Although it rained, we went."], ["EVEN THOUGH", "forte", "início / meio", "Even though it poured, we went."], ["THOUGH", "informal", "início / meio / fim", "We went, though it rained. / It rained, though."], ["ALTHOUGH + BUT na mesma frase.", "", "", ""]], "notes": ["💡 Grau de surpresa: THOUGH (leve) < ALTHOUGH (médio) < EVEN THOUGH (forte). Na fala: THOUGH. Na escrita: ALTHOUGH.", "🔴 ❌ ERRO COMUM: 'Although it rained, but we went out.' — ALTHOUGH e BUT têm o mesmo papel. Nunca use os dois juntos. Use UM ou OUTRO:", "'Although it rained, we went out.' ✅ / 'It rained, but we went out.' ✅", "💡 RESUMO: ALTHOUGH = embora (neutro) | EVEN THOUGH = mesmo que (ênfase) | THOUGH = embora/porém (informal, pode ir no final) | Nunca use"]}], "notes": [], "resumo": "💡 RESUMO: ALTHOUGH = embora (neutro) | EVEN THOUGH = mesmo que (ênfase) | THOUGH = embora/porém (informal, pode ir no final) | Nunca use", "module": 2}, {"file": "10_FOR_EXAMPLE_Por_Exemplo.pdf", "word": "FOR EXAMPLE / FOR INSTANCE / SUCH AS / LIKE", "pt": "POR", "desc": "EXEMPLO / COMO / TAL COMO", "usos": [{"title": "FOR EXAMPLE = POR EXEMPLO (início de frase ou após vírgula)", "num": 1, "header": ["Posição", "Inglês", "Português"], "rows": [["início", "For example, I like outdoor activities.", "Por exemplo, gosto de atividades ao ar livre."], ["início", "For example, you could take a walk.", "Por exemplo, você poderia dar uma caminhada."], ["meio", "I like many sports, for example, soccer.", "Gosto de muitos esportes, por exemplo, futebol."], ["meio", "She speaks languages, for example, French.", "Ela fala idiomas, por exemplo, francês."], ["fim", "Try a new hobby — cooking, for example.", "Experimente um hobby novo — cozinhar, por exemplo."]], "notes": ["💡 FOR EXAMPLE pode vir no início, no meio ou no fim da frase. Sempre separado por vírgulas."]}, {"title": "FOR INSTANCE = POR EXEMPLO (sinônimo, mais formal)", "num": 2, "header": ["Posição", "Inglês", "Português"], "rows": [["início", "For instance, take Brazil — a huge country.", "Por exemplo, pegue o Brasil — um país enorme."], ["meio", "Some animals, for instance dolphins, are smart.", "Alguns animais, por exemplo os golfinhos, são inteligentes."], ["meio", "There are options. For instance, you can walk.", "Há opções. Por exemplo, você pode caminhar."]], "notes": ["💡 FOR INSTANCE = FOR EXAMPLE. São intercambiáveis. FOR INSTANCE é ligeiramente mais formal."]}, {"title": "SUCH AS = COMO / TAL COMO (dentro da frase, lista de exemplos)", "num": 3, "header": ["Estrutura", "Inglês", "Português"], "rows": [["lista", "I like sports such as soccer and tennis.", "Gosto de esportes como futebol e tênis."], ["lista", "Big cities such as São Paulo attract tourists.", "Grandes cidades como São Paulo atraem turistas."], ["lista", "Foods such as rice and beans are popular here.", "Alimentos como arroz e feijão são populares aqui."], ["lista", "She studies subjects such as math and science.", "Ela estuda matérias como matemática e ciências."]], "notes": ["⚠️ SUCH AS fica DENTRO da frase, logo após o substantivo que exemplifica. Não inicia frase."]}, {"title": "LIKE = COMO (informal, exemplos do dia a dia)", "num": 4, "header": ["Estrutura", "Inglês", "Português"], "rows": [["informal", "I enjoy activities like hiking and swimming.", "Gosto de atividades como caminhada e natação."], ["informal", "Cities like Rio are amazing.", "Cidades como o Rio são incríveis."], ["informal", "Do something fun, like watching a movie.", "Faça algo divertido, tipo assistir um filme."]], "notes": ["💡 LIKE (exemplificar) = SUCH AS mas informal. Na fala: LIKE. Na escrita formal: SUCH AS."]}, {"title": "Comparação: FOR EXAMPLE / SUCH AS / LIKE / INCLUDING", "num": 5, "header": ["Palavra", "Posição", "Registro", "Exemplo"], "rows": [["FOR EXAMPLE", "início/meio/fim", "neutro", "I like sports. For example, soccer."], ["FOR INSTANCE", "início/meio", "formal", "For instance, take Brazil."], ["SUCH AS", "dentro da frase", "neutro", "Sports such as soccer are fun."], ["LIKE", "dentro da frase", "informal", "Sports like soccer are fun."], ["INCLUDING", "dentro da frase", "neutro", "Many sports, including soccer, are fun."], ["da frase, informal) | INCLUDING =", "incluindo.", "", ""]], "notes": ["💡 INCLUDING = incluindo. 'Many countries, including Brazil, speak Portuguese.' — lista parcial (não esgota os exemplos).", "🔴 ERRO COMUM: 'I like sports such as soccer, tennis, and etc.' ❌ — Nunca use 'and etc.' em inglês. O correto é apenas 'etc.' ou 'and so on': 'such as", "soccer, tennis, etc.' ✅", "💡 RESUMO: FOR EXAMPLE / FOR INSTANCE = por exemplo (início/meio/fim) | SUCH AS = como/tal como (dentro da frase, formal) | LIKE = como (dentro"]}], "notes": [], "resumo": "💡 RESUMO: FOR EXAMPLE / FOR INSTANCE = por exemplo (início/meio/fim) | SUCH AS = como/tal como (dentro da frase, formal) | LIKE = como (dentro", "module": 2}, {"file": "10_IN_CONCLUSION_Resumindo.pdf", "word": "IN CONCLUSION / TO SUM UP / IN SUMMARY", "pt": "EM", "desc": "CONCLUSÃO / RESUMINDO / EM RESUMO", "usos": [{"title": "IN CONCLUSION = EM CONCLUSÃO (formal, textos escritos)", "num": 1, "header": ["Contexto", "Inglês", "Português"], "rows": [["texto", "In conclusion, English is essential today.", "Em conclusão, o inglês é essencial hoje."], ["texto", "In conclusion, both options have advantages.", "Em conclusão, ambas as opções têm vantagens."], ["texto", "In conclusion, I believe we should act now.", "Em conclusão, acredito que devemos agir agora."], ["apres.", "In conclusion, thank you for your attention.", "Em conclusão, obrigado pela atenção."]], "notes": ["💡 IN CONCLUSION é o mais formal. Usado no parágrafo final de ensaios, redações e apresentações."]}, {"title": "TO SUM UP / IN SUMMARY = RESUMINDO (neutro, fala e escrita)", "num": 2, "header": ["Contexto", "Inglês", "Português"], "rows": [["resumo", "To sum up, we need more time and money.", "Resumindo, precisamos de mais tempo e dinheiro."], ["resumo", "In summary, the plan has three steps.", "Em resumo, o plano tem três etapas."], ["reunião", "To sum up, we decided to postpone.", "Resumindo, decidimos adiar."], ["fala", "To summarize, there are two main options.", "Resumindo, há duas opções principais."]], "notes": ["💡 TO SUM UP é muito usado na fala e em reuniões. IN SUMMARY é mais escrito. Ambos são neutros."]}, {"title": "Outras formas de concluir / encerrar", "num": 3, "header": ["Expressão", "Inglês", "Português"], "rows": [["TO CONCLUDE", "To conclude, I'd like to thank everyone.", "Para concluir, gostaria de agradecer a todos."], ["ALL IN ALL", "All in all, it was a great experience.", "No geral, foi uma ótima experiência."], ["ON THE WHOLE", "On the whole, the plan worked.", "No geral, o plano funcionou."], ["OVERALL", "Overall, I'm satisfied with the result.", "No geral, estou satisfeito com o resultado."], ["IN SHORT", "In short, we failed.", "Em resumo / Em suma, falhamos."], ["IN A NUTSHELL", "In a nutshell, it's complicated.", "Em poucas palavras / Resumindo, é complicado."]], "notes": ["💡 'In a nutshell' = 'em poucas palavras' — muito usada na fala informal. 'Overall' = 'no geral' — versátil e muito comum."]}, {"title": "Comparação de formalidade", "num": 4, "header": ["Expressão", "Registro", "Melhor", "uso"], "rows": [["In conclusion", "muito formal", "textos", "acadêmicos, redações, apresentações"], ["To conclude", "formal", "apresentações,", "discursos formais"], ["In summary", "neutro/formal", "relatórios,", "e-mails profissionais"], ["To sum up", "neutro", "reuniões,", "fala, textos neutros"], ["Overall", "neutro", "fala e escrita,", "muito versátil"], ["All in all", "casual", "conversas,", "textos informais"], ["In a nutshell", "informal", "fala do", "dia a dia"], ["In short", "neutro", "fala e escrita", ""], ["ALL = no geral | IN A NUTSHELL =", "em poucas palavras (informal).", "", ""]], "notes": ["💡 Para e-mails e reuniões: TO SUM UP ou OVERALL. Para redações: IN CONCLUSION. Para conversas: IN A NUTSHELL ou ALL IN ALL.", "🔴 ERRO COMUM: 'In conclusion, I will talk about…' ❌ — IN CONCLUSION vem no FINAL, não no começo. Para introduzir: 'In this text, I will discuss…' ✅", "💡 RESUMO: IN CONCLUSION = em conclusão (formal) | TO SUM UP = resumindo (neutro, fala) | IN SUMMARY = em resumo (escrita) | OVERALL / ALL IN"]}], "notes": [], "resumo": "💡 RESUMO: IN CONCLUSION = em conclusão (formal) | TO SUM UP = resumindo (neutro, fala) | IN SUMMARY = em resumo (escrita) | OVERALL / ALL IN", "module": 2}, {"file": "11_FIRST_THEN_FINALLY_Sequencia.pdf", "word": "FIRST / THEN / NEXT / AFTER THAT / FINALLY", "pt": "", "desc": "", "usos": [{"title": "Sequência completa: início, meio e fim", "num": 1, "header": ["Passo", "Inglês", "Português"], "rows": [["início", "First, wash your hands.", "Primeiro, lave as mãos."], ["início", "First of all, let me introduce myself.", "Primeiramente, deixa eu me apresentar."], ["meio", "Then / Next, add the salt.", "Depois / Em seguida, adicione o sal."], ["meio", "After that, stir for 2 minutes.", "Depois disso, mexa por 2 minutos."], ["fim", "Finally, serve and enjoy.", "Finalmente, sirva e aproveite."], ["fim", "In the end, it was all worth it.", "No final das contas, valeu a pena."]], "notes": ["💡 Use essa sequência para receitas, instruções, histórias e apresentações. Torna o discurso muito mais claro."]}, {"title": "Variações de cada marcador", "num": 2, "header": ["Posição", "Marcadores", "Uso"], "rows": [["início", "First / First of all / To begin with / To start with", "Para começar"], ["meio", "Then / Next / After that / Subsequently / Following this", "Para continuar"], ["meio+", "Also / In addition / Furthermore / Besides", "Para adicionar"], ["fim", "Finally / Lastly / In the end / Last but not least", "Para concluir"]], "notes": ["💡 'Last but not least' = último mas não menos importante — expressão muito usada para mencionar algo final com destaque."]}, {"title": "Sequência em instruções do dia a dia", "num": 3, "header": ["Contexto", "Inglês", "Português"], "rows": [["instrução", "First, open the app. Then, log in.", "Primeiro, abra o app. Depois, entre na conta."], ["instrução", "Next, select your options.", "Em seguida, selecione suas opções."], ["instrução", "After that, click confirm.", "Depois disso, clique em confirmar."], ["instrução", "Finally, check your email.", "Por fim, verifique seu e-mail."]], "notes": ["💡 Sequenciadores são essenciais para dar instruções, contar histórias e fazer apresentações em inglês."]}, {"title": "THEN como consequência (≠ sequência)", "num": 4, "header": ["Uso", "Inglês", "Português"], "rows": [["se…então", "If you study, then you'll pass.", "Se você estudar, então você vai passar."], ["se…então", "If it rains, then we'll stay home.", "Se chover, então ficamos em casa."], ["sequência", "I ate. Then I slept.", "Eu comi. Depois dormi."], ["decisão", "OK, then. Let's go.", "Tudo bem, então. Vamos."], ["britânico e formal.", "", ""], ["também = então (consequência).", "", ""]], "notes": ["⚠️ THEN tem dois usos: sequência (depois) e consequência lógica (então/nesse caso). O contexto define.", "🔴 ERRO COMUM: usar FIRSTLY/SECONDLY/THIRDLY sem necessidade — em inglês americano é mais natural: 'First… Then… Finally'. FIRSTLY é", "💡 RESUMO: FIRST = primeiro | THEN / NEXT = depois / em seguida | AFTER THAT = depois disso | FINALLY / LASTLY = finalmente / por último | THEN"]}], "notes": [], "resumo": "💡 RESUMO: FIRST = primeiro | THEN / NEXT = depois / em seguida | AFTER THAT = depois disso | FINALLY / LASTLY = finalmente / por último | THEN", "module": 2}]};